exercises.solution:
```yaml
{{/*
Chart name, truncated to 63 characters.
*/}}
{{- define "ml-platform.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Fully qualified app name.
*/}}
{{- define "ml-platform.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Chart label.
*/}}
{{- define "ml-platform.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels.
*/}}
{{- define "ml-platform.labels" -}}
helm.sh/chart: {{ include "ml-platform.chart" . }}
{{ include "ml-platform.selectorLabels" . }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

{{/*
Selector labels.
*/}}
{{- define "ml-platform.selectorLabels" -}}
app.kubernetes.io/name: {{ include "ml-platform.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}

{{/*
GPU resources вҖ” conditionally include GPU limits.
*/}}
{{- define "ml-platform.gpuResources" -}}
requests:
  cpu: {{ .Values.resources.requests.cpu | quote }}
  memory: {{ .Values.resources.requests.memory | quote }}
limits:
  cpu: {{ .Values.resources.limits.cpu | quote }}
  memory: {{ .Values.resources.limits.memory | quote }}
  {{- if .Values.gpu.enabled }}
  nvidia.com/gpu: {{ .Values.gpu.count }}
  {{- end }}
{{- end }}
```

```yaml
apiVersion: batch/v1
kind: Job
metadata:
  name: {{ include "hpc-job.fullname" . }}-{{ .Release.Revision }}
  labels:
    {{- include "hpc-job.labels" . | nindent 4 }}
spec:
  completions: {{ .Values.job.completions }}
  parallelism: {{ .Values.job.parallelism }}
  backoffLimit: {{ .Values.job.backoffLimit | default 3 }}
  ttlSecondsAfterFinished: {{ .Values.job.ttlSeconds | default 3600 }}
  template:
    metadata:
      labels:
        {{- include "hpc-job.selectorLabels" . | nindent 8 }}
    spec:
      restartPolicy: Never
      {{- with .Values.nodeSelector }}
      nodeSelector:
        {{- toYaml . | nindent 10 }}
      {{- end }}
      {{- with .Values.tolerations }}
      tolerations:
        {{- toYaml . | nindent 10 }}
      {{- end }}
      containers:
        - name: hpc-worker
          image: "{{ .Values.image.repository }}:{{ .Values.image.tag }}"
          {{- with .Values.job.command }}
          command:
            {{- toYaml . | nindent 16 }}
          {{- end }}
          resources:
            requests:
              cpu: {{ .Values.resources.requests.cpu | quote }}
              memory: {{ .Values.resources.requests.memory | quote }}
            limits:
              cpu: {{ .Values.resources.limits.cpu | quote }}
              memory: {{ .Values.resources.limits.memory | quote }}
              {{- if .Values.gpu.enabled }}
              nvidia.com/gpu: {{ .Values.gpu.count }}
              {{- end }}
          {{- if .Values.volumes.data.enabled }}
          volumeMounts:
            - name: data
              mountPath: {{ .Values.volumes.data.mountPath }}
              readOnly: {{ .Values.volumes.data.readOnly | default false }}
          {{- end }}
      {{- if .Values.volumes.data.enabled }}
      volumes:
        - name: data
          persistentVolumeClaim:
            claimName: {{ .Values.volumes.data.pvcName }}
      {{- end }}
```
